    ('Genusswelt', 'Antipasticreme - Bärlauch', 'https://images.openfoodfacts.org/images/products/000/004/243/6430/front_de.16.400.jpg', 'off_api', 'front', true, 'Front — EAN 42436430', 'front_42436430'),
    ('NENI am Tisch', 'Hummus mit Olivenöl & Kichererbsen', 'https://images.openfoodfacts.org/images/products/912/005/167/0876/front_en.12.400.jpg', 'off_api', 'front', true, 'Front — EAN 9120051670876', 'front_9120051670876'),
    ('Followfood', 'Followfood Kürbis Hummus 4260655550237 Bio Kichererbsenaufstrich', 'https://images.openfoodfacts.org/images/products/426/065/555/0237/front_de.42.400.jpg', 'off_api', 'front', true, 'Front — EAN 4260655550237', 'front_4260655550237'),
    ('Clarkys', 'Salsa Käse im glas', 'https://images.openfoodfacts.org/images/products/000/004/245/7657/front_en.10.400.jpg', 'off_api', 'front', true, 'Front — EAN 42457657', 'front_42457657'),
    ('Unknown', 'Bruschetta Aufstrich gegrillte Paprika', 'https://images.openfoodfacts.org/images/products/406/145/809/8359/front_de.3.400.jpg', 'off_api', 'front', true, 'Front — EAN 4061458098359', 'front_4061458098359')
) AS d(brand, product_name, url, source, image_type, is_primary, alt_text, off_image_id)
JOIN products p ON p.country = 'DE' AND p.brand = d.brand AND p.product_name = d.product_name
  AND p.category = 'Spreads & Dips' AND p.is_deprecated IS NOT TRUE
ON CONFLICT (off_image_id) WHERE off_image_id IS NOT NULL DO UPDATE SET
  url = EXCLUDED.url,
  image_type = EXCLUDED.image_type,
  is_primary = EXCLUDED.is_primary,
  alt_text = EXCLUDED.alt_text;
